#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long A, B;
        scanf("%lld %lld", &A, &B);
        printf("%lld\n", A + B);
    }
    return 0;
}

